
import { ref, defineComponent, reactive, toRaw, toRefs } from "vue";
import { UploadOutlined } from "@ant-design/icons-vue";
import { postAnnounce } from "@/server/http/api/system";
export default defineComponent({
  components: {
    UploadOutlined,
  },
  setup() {
    const visible = ref<boolean>(false);
    const confirmLoading = ref<boolean>(false);
    const fileList = ref<any[]>([]);
    const formRef = ref();
    const formState: any = reactive({
      spreadhead: "",
      ncontentDetail: "",
    });
    const rules = {
      spreadhead: [
        {
          required: true,
          message: "标题为必填项",
          trigger: "blur",
        },
        {
          min: 3,
          max: 20,
          message: "长度在3-20个字符",
          trigger: "change",
        },
      ],
    };

    const showModal = () => {
      visible.value = true;
    };

    const handleOk = () => {
      confirmLoading.value = true;

      formRef.value
        .validate()
        .then(() => {
          let Files = new FormData();

          fileList.value.forEach((file: any) => {
            Files.append("file", file);
          });
          Files.append("json", JSON.stringify(toRaw(formState)));
          postAnnounce(Files)
            .then((res: any) => {
              if (res.data.code === 200) {
                formState.spreadhead = "";
                formState.ncontentDetail = "";
                fileList.value = [];
              }
              visible.value = false;
              confirmLoading.value = false;
            })
            .catch(() => {
              visible.value = false;
              confirmLoading.value = false;
            });
        })
        .catch((error: any) => {
          visible.value = false;
          confirmLoading.value = false;
        });
    };
    const handleRemove = (file: any) => {
      const index = fileList.value.indexOf(file);
      const newFileList = fileList.value.slice();
      newFileList.splice(index, 1);
      fileList.value = newFileList;
    };
    const beforeUpload = (file: any) => {
      fileList.value = [...fileList.value, file];
      return false;
    };

    return {
      visible,
      confirmLoading,
      showModal,
      handleOk,
      fileList,
      handleRemove,
      beforeUpload,
      formState,
      rules,
      formRef,
      labelCol: { span: 6 },
      wrapperCol: { span: 14 },
    };
  },
});
